import{aj as b,C as r,o as I,c as l,ai as L,E as G,w as N,j as t,t as z,e as P,a as F,k as g,a0 as h,p as W}from"./chunks/framework.BEkJ3Og3.js";import{C as n}from"./chunks/ConceptTree.Dqf0nzHj.js";import{c as R}from"./chunks/index.ChDO1HXp.js";import"./chunks/utils.BqHq3bD_.js";import"./chunks/ItemList.COrBn9y7.js";import"./chunks/ItemName.Bg-1XmoY.js";/* empty css                      */import"./chunks/LoadingIndicator.CKimPMUe.js";import"./chunks/vue-scrollto.CmbikFEE.js";import"./chunks/Arrow.DUT_CERB.js";const S={key:0},Y={key:1},M={key:2},u=["onClick"],y=["onClick"],D=JSON.parse('{"title":"ConceptTree","description":"","frontmatter":{},"headers":[],"relativePath":"components/ConceptTree.md","filePath":"components/ConceptTree.md"}'),k={name:"components/ConceptTree.md"},Q=Object.assign(k,{setup(U){const s=R.initializeRegistry({provider:"ConceptApi",api:"https://coli-conc.gbv.de/api/"}),j={uri:"https://www.ixtheo.de/classification/"},e=W(null),o=W(""),i=b("conceptTree");return(C,c)=>{const p=r("ComponentView");return I(),l("div",null,[c[4]||(c[4]=L('<h1 id="concepttree" tabindex="-1">ConceptTree <a class="header-anchor" href="#concepttree" aria-label="Permalink to &quot;ConceptTree&quot;">​</a></h1><p>Component to display a concept tree with hierarchy from concept field <code>narrower</code>. The tree is based on <a href="./ItemList.html">ItemList</a> and derives all of its slots and methods. The component supports:</p><ul><li>selecting a concept (prop <code>v-model</code>)</li><li>expanding/collapsing nodes (events <code>open</code> / <code>close</code>)</li><li>programmatic scrolling (method <code>scrollToUri</code>)</li><li>programmatic navigation in the hierarchy (method <a href="#navigatetouri"><code>navigateToUri</code></a>)</li><li>dynamic loading additional concepts (props <code>registry</code> and <code>scheme</code>)</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><ul><li><code>modelValue</code> <em>object, v-model, default <code>null</code></em> — currently selected concept (highlighted)</li><li><code>concepts</code> <em>array, default <code>null</code></em> — JSKOS concepts to be displayed (usually top concepts). Optional if registry and scheme are provided.</li><li><code>hierarchy</code> <em>boolean, default <code>true</code></em> — whether to display concept hierarchy (via <code>narrower</code>)</li><li><code>itemListOptions</code> <em>object, default <code>{}</code></em> — options passed through to <a href="./ItemList.html"><code>ItemList</code></a> via <code>v-bind</code></li><li><code>registry</code> <em>object, default <code>null</code></em> — Registry to load concepts from</li><li><code>scheme</code> <em>object, default <code>null</code></em> — Concept Scheme to load concepts from. Must have field <code>uri</code> or <code>identifier</code> at least.</li></ul><h2 id="concept-loading" tabindex="-1">Concept loading <a class="header-anchor" href="#concept-loading" aria-label="Permalink to &quot;Concept loading&quot;">​</a></h2><p>Either <code>concepts</code> or both of <code>registry</code> and <code>scheme</code> are required to show the concept tree. If <code>registry</code> is not set, it is taken from internal field <code>_registry</code> or <code>inScheme[0]._registry</code> of the first concept. A registry object should have the following methods to load concepts from given scheme URI or concept URI:</p><ul><li><code>getConcepts({ concepts: [{ uri }] })</code> — load concept details</li><li><code>getTop({ scheme: { uri } })</code> — load top concepts (only required when prop <code>concepts</code> is not set)</li><li><code>getNarrower({ concept: { uri } })</code> — load narrower concepts (only required when <code>getConcepts</code> does not include full field <code>narrower</code> for every concept)</li></ul><p>See <a href="https://github.com/gbv/cocoda-sdk" target="_blank" rel="noreferrer">cocoda-sdk</a> for a library that provides registry objects for various terminology APIs.</p><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to &quot;Slots&quot;">​</a></h2><p>The slots are forwarded to the corresponding <a href="./ItemList.html#slots">slots of ItemList</a>:</p><ul><li><code>beforeList</code> — content shown above the list.</li><li><code>afterList</code> — content shown below the list.</li><li><code>beforeItem</code> — content shown before an item <em>(slot prop: <code>{ item }</code> where <code>item</code> is the concept)</em>.</li><li><code>afterItem</code> — content shown after an item <em>(slot prop: <code>{ item }</code> where <code>item</code> is the concept)</em>.</li></ul><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><p>The <a href="./ItemList.html#methods">methods of ItemList</a> are exposed to be used on a component reference.</p><ul><li><code>isUriInView</code> — see <a href="./ItemList.html#methods">ItemList</a></li><li><code>scrollToUri</code> — see <a href="./ItemList.html#methods">ItemList</a></li><li><a href="#navigatetouri"><code>navigateToUri</code></a> — navigate to a concept in the hierarchy</li><li><a href="#open"><code>open</code></a> — open a concept and load narrower concepts if needed</li><li><a href="#close"><code>close</code></a> — close an opened concept</li><li><a href="#collapse"><code>collapse</code></a> — close all opened concepts</li></ul><h3 id="navigatetouri" tabindex="-1">navigateToUri <a class="header-anchor" href="#navigatetouri" aria-label="Permalink to &quot;navigateToUri&quot;">​</a></h3><p>Navigate to a concept in the hierarchy with loading missing concepts. If the concept is already rendered, it is scrolled to (and optionally selected). Otherwise the function tries to open the path from the top concepts down to the target using by loading narrower concepts. Returns a Promise with boolean <code>true</code> if navigation succeeded, <code>false</code> otherwise. Method arguments:</p><ul><li><code>uriOrConcept</code> <em>string | { uri: string }</em> — the concept URI to navigate to</li><li><code>options</code> <em>object, optional</em><ul><li><code>select</code> <em>boolean, default <code>true</code></em> — whether to set <code>modelValue</code> to the target concept</li><li><code>onlyIfNotInView</code> <em>boolean, default <code>true</code></em> — pass-through to <code>scrollToUri</code></li></ul></li></ul><p><strong>Returns</strong> a Promise resolving to <code>true</code> if navigation succeeded, <code>false</code> otherwise.</p><h3 id="close" tabindex="-1">close <a class="header-anchor" href="#close" aria-label="Permalink to &quot;close&quot;">​</a></h3><p>Close an opened concept. Requires concept object with field <code>uri</code>. Note that parents of selected concepts cannot be closed.</p><h3 id="collapse" tabindex="-1">collapse <a class="header-anchor" href="#collapse" aria-label="Permalink to &quot;collapse&quot;">​</a></h3><p>Close all opened concepts. Note that parents of selected concepts cannot be closed.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><ul><li><code>select</code> emitted when a concept is selected. Note that <code>update:modelValue</code> is also emitted each time selection changes. Parameter is the same payload as <code>ItemList</code>’s <code>select</code> event: an object with properties: <ul><li><code>item</code> (the clicked concept)</li><li><code>row</code> (<code>true</code> when the click was initiated via the row, not on the item directly)</li></ul></li><li><code>open</code> emitted when a concept’s narrower concepts are opened. Parameter is the concept.</li><li><code>close</code> emitted when a concept’s narrower concepts are closed. Parameter is the concept.</li><li><code>update:modelValue</code> Used for v-model updates. Will always be emitted together with <code>select</code> when selection changes.</li></ul><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><ul><li><code>.jskos-vue-conceptTree</code> — the component element</li><li><code>.jskos-vue-conceptTree-arrow</code> — arrow to expand/collapse a subtree</li><li><code>.jskos-vue-conceptTree-depthSpacer</code> — vertical line left to expanded subtrees</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2>',28)),G(p,{src:"",highlightedSrc:""},{default:N(()=>[t("template",null,[t("p",null,[t("button",{onClick:c[0]||(c[0]=a=>i.value.navigateToUri("https://www.ixtheo.de/classification/VB"))}," Navigate to VB Hermeneutik ; Philosophie "),t("button",{onClick:c[1]||(c[1]=a=>i.value.collapse())}," Collapse tree ")]),o.value?(I(),l("p",S,z(o.value),1)):P("",!0),e.value?.uri?(I(),l("p",Y,[F(" Selected: "+z(e.value.uri)+" ",1),t("button",{onClick:c[2]||(c[2]=a=>i.value.scrollToUri(e.value.uri))}," Scroll to selected ")])):(I(),l("p",M," Please select a concept. ")),G(n,{ref_key:"conceptTree",ref:i,modelValue:e.value,"onUpdate:modelValue":c[3]||(c[3]=a=>e.value=a),registry:g(s),scheme:j,style:{height:"400px","overflow-y":"auto",border:"2px solid #0001"}},{beforeItem:N(a=>[t("span",{class:"opacity-hover",style:{"margin-right":"5px"},onClick:h(d=>o.value=`Clicked on Star for item ${a.item.uri}`,["stop"])}," ⭐️ ",8,u)]),afterItem:N(a=>[t("div",{class:"opacity-hover",style:{position:"absolute",width:"20px",right:"2px",top:"50%",transform:"translateY(-50%)"},onClick:h(d=>o.value=`Clicked on Rocket for item ${a.item.uri}`,["stop"])}," 🚀 ",8,y)]),_:1},8,["modelValue","registry"])])]),_:1})])}}});export{D as __pageData,Q as default};
